// // This module takes 3 inputs and produces 2 outputs. It has inputs A, B, and C, and outputs X and Y. When A is 1, X is 1 and Y is the logical OR of B and C. When A is 0, X is 0 and Y is the logical AND of B and C.
module three_to_two (
    input A,
    input B,
    input C,
    output X,
    output Y
);

    assign X = A ? 1 : 0;
    assign Y = A ? (B & C) : (B | C);

endmodule
